200→+/**
201→+ * One-time initialization hook for the connection state machine.
202→+ *
203→+ * Call this once in MainLayout (or equivalent top-level component).
204→+ * Subscribes to WS connection changes and send-attempt-failed events,
205→+ * and drives the Zustand store transitions.
206→+ */
207→+
208→+import { useEffect } from "react";
209→+import { isConnected, onConnectionChange } from "@/platform/ws";
210→+import { onSendAttemptFailed } from "../lib/connectionEvents";
211→+import { useConnectionStore } from "../store/connectionStore";
212→+
213→+export function useConnectionStateInit() {
214→+  useEffect(() => {
215→+    if (isConnected() && useConnectionStore.getState().state !== "connected") {
216→+      useConnectionStore.getState().onConnected();
217→+    }
218→+
219→+    const unsubConnection = onConnectionChange((connected) => {
220→+      if (connected) {
221→+        useConnectionStore.getState().onConnected();
222→+      } else {
223→+        useConnectionStore.getState().onDisconnected();
224→+      }
225→+    });
226→+
227→+    const unsubSendFailed = onSendAttemptFailed(() => {
228→+      useConnectionStore.getState().markSendAttemptFailed();
229→+    });
230→+
231→+    return () => {
232→+      unsubConnection();
233→+      unsubSendFailed();
234→+    };
235→+  }, []);
236→+}
