257→+/**
258→+ * Tiny event emitter for cross-feature connection signals.
259→+ *
260→+ * Session actions call emitSendAttemptFailed() when a command rejects
261→+ * because the WebSocket is down. The connection store listens and
262→+ * immediately escalates to DISCONNECTED state.
263→+ */
264→+
265→+type Listener = () => void;
266→+
267→+const listeners = new Set<Listener>();
268→+
269→+export function emitSendAttemptFailed(): void {
270→+  for (const fn of listeners) fn();
271→+}
272→+
273→+export function onSendAttemptFailed(cb: Listener): () => void {
274→+  listeners.add(cb);
275→+  return () => {
276→+    listeners.delete(cb);
277→+  };
278→+}
279→diff --git a/apps/web/src/features/connection/store/connectionStore.ts b/apps/web/src/features/connection/store/connectionStore.ts
280→new file mode 100644
281→index 000000000..44b454887
282→--- /dev/null
283→+++ b/apps/web/src/features/connection/store/connectionStore.ts
284→@@ -0,0 +1,98 @@
285→+/**
286→+ * Connection state machine — Zustand store.
287→+ *
288→+ * States:
289→+ *   CONNECTED     → healthy, all systems go
290→+ *   GRACE_PERIOD  → WS just dropped, wait 2s before showing anything
291→+ *   RECONNECTING  → 2-30s, show thin reconnecting bar
292→+ *   DISCONNECTED  → 30s+, show full banner, dim content
293→+ *
294→+ * Escalation shortcuts:
295→+ *   - If a sendCommand fails while in GRACE_PERIOD or RECONNECTING,
296→+ *     immediately jump to DISCONNECTED (user tried to act).
297→+ */
298→+
299→+import { create } from "zustand";
300→+import { forceReconnect } from "@/platform/ws";
301→+
302→+const GRACE_MS = 2_000;
303→+const ESCALATE_MS = 30_000;
304→+
305→+export type ConnectionState = "connected" | "grace_period" | "reconnecting" | "disconnected";
306→+
307→+interface ConnectionStore {
308→+  state: ConnectionState;
309→+  disconnectedAt: number | null;
310→+  sendAttemptFailed: boolean;
311→+  onConnected: () => void;
312→+  onDisconnected: () => void;
313→+  markSendAttemptFailed: () => void;
314→+  retry: () => void;
315→+}
316→+
317→+// Module-level timer refs (not serializable, don't belong in store state)
318→+let graceTimer: ReturnType<typeof setTimeout> | null = null;
319→+let escalateTimer: ReturnType<typeof setTimeout> | null = null;
320→+
321→+function clearTimers() {
322→+  if (graceTimer) {
323→+    clearTimeout(graceTimer);
324→+    graceTimer = null;
325→+  }
326→+  if (escalateTimer) {
327→+    clearTimeout(escalateTimer);
328→+    escalateTimer = null;
329→+  }
330→+}
331→+
332→+export const useConnectionStore = create<ConnectionStore>((set, get) => ({
333→+  state: "connected",
334→+  disconnectedAt: null,
335→+  sendAttemptFailed: false,
336→+
337→+  onConnected: () => {
338→+    clearTimers();
339→+    set({ state: "connected", disconnectedAt: null, sendAttemptFailed: false });
340→+  },
341→+
342→+  onDisconnected: () => {
343→+    const current = get().state;
344→+    // Don't re-enter if already in the active disconnection flow (grace/reconnecting).
345→+    // Allow re-entry from "disconnected" so that Retry → forceReconnect → onclose
346→+    // can restart the grace period.
347→+    if (current === "grace_period" || current === "reconnecting") return;
348→+
349→+    clearTimers();
350→+    set({ state: "grace_period", disconnectedAt: Date.now(), sendAttemptFailed: false });
351→+
352→+    graceTimer = setTimeout(() => {
353→+      if (get().state !== "grace_period") return;
354→+
355→+      set({ state: "reconnecting" });
356→+
357→+      // Escalate to DISCONNECTED after ESCALATE_MS total from initial disconnect
358→+      // (not from entering RECONNECTING). Accounts for time already in GRACE_PERIOD.
359→+      const disconnectedAt = get().disconnectedAt;
360→+      if (!disconnectedAt) return;
361→+
362→+      const remaining = Math.max(0, ESCALATE_MS - (Date.now() - disconnectedAt));
363→+      escalateTimer = setTimeout(() => {
364→+        if (get().state === "reconnecting") {
365→+          set({ state: "disconnected" });
366→+        }
367→+      }, remaining);
368→+    }, GRACE_MS);
369→+  },
370→+
371→+  markSendAttemptFailed: () => {
372→+    const current = get().state;
373→+    if (current === "grace_period" || current === "reconnecting") {
374→+      clearTimers();
375→+      set({ state: "disconnected", sendAttemptFailed: true });
376→+    }
377→+  },
378→+
379→+  retry: () => {
380→+    forceReconnect();
381→+  },
382→+}));
